const devInfo = $("Get Linked PRs").first().json;
const details = devInfo.detail || [];

// Recopilar todos los PRs mergeados
const mergedPRs = [];
for (const d of details) {
  const prs = d.pullRequests || [];
  for (const pr of prs) {
    if (pr.status === "MERGED") {
      // Extraer workspace y repo de la URL del PR
      const decodedUrl = decodeURIComponent(pr.url);
      const cleanPath = decodedUrl
        .replace("https://bitbucket.org/", "");
      const parts = cleanPath.split("/");
      const workspace = parts[0];
      const repoSlug = parts[1];
      const prId = parts[3] || pr.id;

      mergedPRs.push({
        prId,
        prName: pr.name || "",
        prUrl: decodedUrl,
        workspace,
        repoSlug,
        sourceBranch: pr.source?.branch || "",
        destinationBranch: pr.destination?.branch || "",
        author: pr.author?.name || "No disponible",
        // URLs de la API de Bitbucket
        diffUrl: `https://api.bitbucket.org/2.0/repositories/${workspace}/${repoSlug}/pullrequests/${prId}/diff`,
        commitsUrl: `https://api.bitbucket.org/2.0/repositories/${workspace}/${repoSlug}/pullrequests/${prId}/commits`,
      });
    }
  }
}

// Si no hay PRs mergeados, pasar un flag para saltear
// la parte de Bitbucket
return [{
  json: {
    mergedPRs,
    hasPRs: mergedPRs.length > 0,
    prCount: mergedPRs.length
  }
}];

// ==========================================
// DATOS DE JIRA
// ==========================================
const hu = $("Get HU Details").first().json;
const epic = $("Get Parent Epic").first().json;

const huKey = hu.key;
const huSummary = hu.fields.summary;
const huDescription = hu.fields.description || "Sin descripción";
const epicName = epic.fields.summary;

// Función para extraer texto de comentarios (ADF o plano)
function extractText(body) {
  if (typeof body === "string") return body;
  if (typeof body === "object" && body.content) {
    return body.content
      .map(block => {
        if (block.content) {
          return block.content
            .map(inline => inline.text || "").join("");
        }
        return "";
      })
      .join("\n");
  }
  return "(vacío)";
}

// Comentarios de la HU
let huComments = [];
try {
  const data = $("Get HU Comments").first().json;
  huComments = (data.comments || []).map(c => ({
    source: `HU ${huKey}`,
    author: c.author?.displayName || "Desconocido",
    text: extractText(c.body)
  }));
} catch(e) {}

// Comentarios de subtareas
let subtaskComments = [];
try {
  const stItems = $("Get Subtask Comments").all();
  for (const item of stItems) {
    const comments = item.json.comments || [];
    for (const c of comments) {
      subtaskComments.push({
        source: "Subtarea",
        author: c.author?.displayName || "Desconocido",
        text: extractText(c.body)
      });
    }
  }
} catch(e) {}

// Info de subtareas
let subtasksInfo = [];
try {
  const subtasks = $("Get Subtasks").all();
  subtasksInfo = subtasks.map(st => ({
    key: st.json.key,
    summary: st.json.fields?.summary || "",
    status: st.json.fields?.status?.name || "",
    assignee: st.json.fields?.assignee?.displayName 
      || "Sin asignar"
  }));
} catch(e) {}

// ==========================================
// DATOS DE BITBUCKET
// ==========================================
let prInfo = [];
try {
  prInfo = $("Extract PR Info").first().json.mergedPRs || [];
} catch(e) {}

// Diffs de PRs
let allDiffs = "";
try {
  const diffItems = $("Get PR Diff").all();
  for (const item of diffItems) {
    const diffText = typeof item.json === "string" 
      ? item.json 
      : (item.json.data || JSON.stringify(item.json));
    allDiffs += diffText + "\n\n";
  }
} catch(e) {}

// Truncar diffs si son muy largos
const MAX_DIFF = 12000;
if (allDiffs.length > MAX_DIFF) {
  allDiffs = allDiffs.substring(0, MAX_DIFF) 
    + "\n\n... [DIFF TRUNCADO] ...";
}

// Commits de PRs
let allCommits = [];
try {
  const commitItems = $("Get PR Commits 2").all();
  for (const item of commitItems) {
    const values = item.json.values || [];
    for (const c of values) {
      allCommits.push({
        hash: c.hash?.substring(0, 8),
        message: c.message,
        author: c.author?.raw 
          || c.author?.user?.display_name || ""
      });
    }
  }
} catch(e) {}

// ==========================================
// ARMAR PROMPT UNIFICADO
// ==========================================
const commentsSummary = [
  ...huComments.map(c => 
    `[${c.source}] ${c.author}: ${c.text}`),
  ...subtaskComments.map(c => 
    `[${c.source}] ${c.author}: ${c.text}`)
].join("\n");

const subtasksSummary = subtasksInfo
  .map(st => 
    `- ${st.key}: ${st.summary} (${st.status}, ${st.assignee})`)
  .join("\n");

const prSummary = prInfo.map(pr => 
  `- PR #${pr.prId}: ${pr.prName} | ${pr.workspace}/${pr.repoSlug} | ${pr.sourceBranch} → ${pr.destinationBranch} | Autor: ${pr.author}`
).join("\n");

const commitsSummary = allCommits
  .map(c => `[${c.hash}] ${c.message} (${c.author})`)
  .join("\n");

const agentPrompt = `
Analizá toda la información de esta Historia de Usuario
completada y generá documentación técnica UNIFICADA en
español para actualizar la página de Confluence del proyecto.

## HISTORIA DE USUARIO
- Clave: ${huKey}
- Resumen: ${huSummary}
- Descripción: ${huDescription}
- Epic/Proyecto: ${epicName}

## SUBTAREAS (${subtasksInfo.length})
${subtasksSummary || "Sin subtareas"}

## COMENTARIOS DEL EQUIPO (${huComments.length + subtaskComments.length})
${commentsSummary || "Sin comentarios"}

## PULL REQUESTS MERGEADOS (${prInfo.length})
${prSummary || "Sin PRs vinculados (la HU puede no tener código asociado)"}

## COMMITS (${allCommits.length})
${commitsSummary || "Sin commits"}

## DIFF DEL CÓDIGO
${allDiffs || "Sin diff disponible"}

## INSTRUCCIONES
Generá UN SOLO bloque HTML unificado que integre toda la
información anterior. La estructura debe ser:

1. <h2> con la clave y resumen de la HU
2. Metadata: tabla con estado, fecha, repositorio(s), rama(s)
3. Descripción funcional: qué se implementó según la HU
4. Tabla de subtareas (si hay)
5. Cambios técnicos: archivos modificados, lógica de negocio,
   validaciones, integraciones (basado en el diff y commits)
6. Notas del desarrollador: información relevante de los
   comentarios de devs (avances, aclaraciones técnicas)
7. Notas de QA: resultados de pruebas, documentos de prueba,
   bugs encontrados (de los comentarios de QA/testers)
8. Observaciones: puntos importantes que surjan del análisis

Para clasificar comentarios:
- Si el autor tiene "QA", "Tester" o "Test" → sección QA
- El resto → sección Desarrollador

Si no hay PRs/código, omití las secciones técnicas y
enfocate en la parte funcional y los comentarios.

Formato: HTML válido para Confluence con <h2>, <h3>, <p>,
<ul><li>, <table>. NO uses markdown.
`;

return [{
  json: {
    agentPrompt,
    epicName,
    huKey,
    huSummary
  }
}];

// Reducir a 1 solo item para que el resto
// de la cadena se ejecute una sola vez.
// No perdemos datos porque Consolidate All Data
// accede a cada nodo por nombre con $("NombreNodo")
return [{ json: { status: "comments_collected" } }];

const consolidatedData = $("Consolidate All Data").first().json;
const searchResults = $("Find Confluence Page").first().json;
const results = searchResults.results || [];
const epicName = consolidatedData.epicName;

const matchingPages = results.filter(
  page => page.title === epicName
);

if (matchingPages.length === 0) {
  throw new Error(
    `No se encontró página con título "${epicName}".`
  );
}

const page = matchingPages[0];
const pageId = page.id;
const pageVersion = page.version.number;
const pageTitle = page.title;
const currentPageContent = page.body.storage.value;

// ==========================================
// LIMPIAR HTML: sacar macros y bloat de Confluence
// que no son relevantes para el análisis
// ==========================================
function cleanConfluenceHtml(html) {
  let clean = html;

  // Remover macros de Confluence (ac:structured-macro)
  // que son de UI/templates, no contenido técnico
  clean = clean.replace(
    /<ac:structured-macro[^>]*ac:name="(panel|info|expand|recently-updated|livesearch|listlabels|blog-posts|status|details|task-list)"[^]*?<\/ac:structured-macro>/gs,
    ""
  );

  // Remover layouts de Confluence
  clean = clean.replace(/<ac:layout[^>]*>/g, "");
  clean = clean.replace(/<\/ac:layout>/g, "");
  clean = clean.replace(/<ac:layout-section[^>]*>/g, "");
  clean = clean.replace(/<\/ac:layout-section>/g, "");
  clean = clean.replace(/<ac:layout-cell[^>]*>/g, "");
  clean = clean.replace(/<\/ac:layout-cell>/g, "");

  // Remover emojis de Confluence
  clean = clean.replace(/<ac:emoticon[^>]*\/>/g, "");

  // Remover imágenes externas de Confluence
  clean = clean.replace(/<ac:image[^]*?\/>/gs, "");
  clean = clean.replace(/<ac:image[^]*?<\/ac:image>/gs, "");
  clean = clean.replace(/<ri:url[^>]*\/>/g, "");

  // Remover placeholders
  clean = clean.replace(/<ac:placeholder[^>]*>[^]*?<\/ac:placeholder>/gs, "");

  // Remover task lists de template
  clean = clean.replace(/<ac:task-list>[^]*?<\/ac:task-list>/gs, "");

  // Remover atributos local-id, data-*, ac:local-id
  clean = clean.replace(/\s+(local-id|data-[a-z-]+|ac:local-id|ac:macro-id|ac:schema-version)="[^"]*"/g, "");

  // Remover fieldset
  clean = clean.replace(/<fieldset[^>]*>[^]*?<\/fieldset>/gs, "");

  // Remover líneas vacías múltiples
  clean = clean.replace(/\n{3,}/g, "\n\n");

  // Remover tags vacíos
  clean = clean.replace(/<p\s*\/>/g, "");
  clean = clean.replace(/<p>\s*<\/p>/g, "");

  return clean.trim();
}

const cleanedContent = cleanConfluenceHtml(currentPageContent);

// Truncar si sigue siendo muy largo
const MAX_PAGE_CHARS = 8000;
let pageForPrompt = cleanedContent;
if (pageForPrompt.length > MAX_PAGE_CHARS) {
  pageForPrompt = pageForPrompt.substring(0, MAX_PAGE_CHARS)
    + "\n\n... [DOCUMENTO TRUNCADO POR LONGITUD] ...";
}

const today = new Date().toISOString().split("T")[0];

const fullPrompt = `
Analizá la siguiente Historia de Usuario completada y
actualizá el documento técnico de Confluence.

## HISTORIA DE USUARIO
- Clave: ${consolidatedData.huKey}
- Resumen: ${consolidatedData.huSummary}
- Epic: ${epicName}
- Fecha: ${today}

## SUBTAREAS, COMENTARIOS Y CÓDIGO
${consolidatedData.agentPrompt}

## DOCUMENTO TÉCNICO ACTUAL
<DOCUMENTO_ACTUAL>
${pageForPrompt}
</DOCUMENTO_ACTUAL>

## INSTRUCCIONES

1. Devolvé el documento HTML COMPLETO actualizado.
   Tu respuesta REEMPLAZA todo el contenido de la página.

2. PRESERVÁ todo el contenido existente que siga válido.

3. Si ya existe una sección para ${consolidatedData.huKey}
   (buscá 📋 seguido de la clave), EDITALA en vez de
   agregar una nueva.

4. Si un comentario o descripción CORRIGE información
   existente, ACTUALIZÁ el dato donde está.

5. Si la información es NUEVA, integrala en la sección
   correspondiente o creá una nueva.

6. Incluí al final de cada sección de NexusDocs:
   <p><em>NexusDocs: ${today} | ${consolidatedData.huKey}</em></p>

7. HTML válido para Confluence: <h2>, <h3>, <p>, <ul><li>,
   <table>. NO markdown. NO bloques de código.
   NO incluyas \`\`\`html ni \`\`\` en tu respuesta.
`;

return [{
  json: {
    fullPrompt,
    epicName,
    huKey: consolidatedData.huKey,
    huSummary: consolidatedData.huSummary,
    pageId,
    pageVersion,
    pageTitle,
    currentPageContent  // guardamos el original para fallback
  }
}];

const context = $("Prepare Full Context").first().json;

// Obtener respuesta del agente
let updatedContent = "";
try {
  updatedContent = $("AI Agent Unified").first().json.output
    || $("AI Agent Unified").first().json.text || "";
} catch(e) {
  updatedContent = "";
}

// Si usaste HTTP Request a OpenAI en vez de AI Agent
if (!updatedContent) {
  try {
    const resp = $("AI Agent Unified").first().json;
    updatedContent = resp.choices?.[0]?.message?.content || "";
  } catch(e) {}
}

// Limpiar bloques de código si el agente los agregó
updatedContent = updatedContent
  .replace(/^```html?\s*/i, "")
  .replace(/\s*```\s*$/i, "")
  .trim();

// SEGURIDAD: Si el agente devolvió vacío o muy corto,
// no reemplazar el documento (evitar borrar contenido)
if (updatedContent.length < 50) {
  throw new Error(
    "El agente devolvió contenido vacío o muy corto. " +
    "Se cancela la actualización para proteger el documento. " +
    `Largo recibido: ${updatedContent.length} caracteres.`
  );
}

const confluenceBody = {
  id: context.pageId,
  type: "page",
  title: context.pageTitle,
  version: {
    number: context.pageVersion + 1
  },
  body: {
    storage: {
      value: updatedContent,
      representation: "storage"
    }
  }
};

return [{
  json: {
    confluenceBody,
    pageId: context.pageId
  }
}];
